// Sum RRF score function
function sum_rrf_score(row) {
    return row.reduce((sum, val) => sum + val, 0); // Example: sum of row values
}

// Main function
function processMatrix(matrix, selection) {
    // Step 1: Select columns and rows, and track original indices
    const selectedWithIndices = matrix.map((row, idx) => ({
        originalIndex: idx,
        selectedRow: selection.map(colIdx => row[colIdx])
    }));

    // Step 2: Drop rows where index is in selection
    const filteredWithIndices = selectedWithIndices.filter(row => !selection.includes(row.originalIndex));

    // Step 3: Rank rows in descending order (using sum of rrf_score)
    const rankedRows = filteredWithIndices.map(({ originalIndex, selectedRow }) => ({
        originalIndex,
        selectedRow,
        score: sum_rrf_score(selectedRow)
    })).sort((a, b) => b.score - a.score);

    // Step 4: Sum values across each row (if needed)
    const summedScores = rankedRows.map(({ originalIndex, selectedRow, score }) => ({
        originalIndex,
        selectedRow,
        score: selectedRow.reduce((sum, val) => sum + val, 0) // Example: sum of row values
    }));

    // Step 5: Sort the results
    const sortedResults = summedScores.sort((a, b) => b.score - a.score);

    return sortedResults;
}

function retrieveTopResult(matrix, selection){
    return processMatrix(matrix, selection)[0].originalIndex
}

function retrieveTop4Results(matrix, selection){
    let results = processMatrix(matrix, selection)
    let top4 = [0,1,2,3].map(x=>results[x])

    return top4.map(a => a.originalIndex) ///processMatrix(matrix, selection)[0].originalIndex
}

